import { quote, claim } from "./mhpco.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - Base Premiums", () => {
    it.todo("should calculate empty item list premium (only processing fee)");
    it.todo("should calculate single sword premium");
    it.todo("should calculate single amulet premium");
    it.todo("should calculate single staff premium");
    it.todo("should calculate single potion premium");
    it.todo("should calculate single component premium");
    it.todo("should calculate multiple items premium (sum of base premiums + fee)");
  });

  describe("Quote - Processing Fee", () => {
    it.todo("should add 5 G processing fee to every premium");
  });

  describe("Claim - Deductible", () => {
    it.todo("should apply 100 G deductible per damage event");
    it.todo("should process damage to single item with deductible");
    it.todo("should process damage to multiple items (deductible per item)");
  });

  describe("Claim - Cap", () => {
    it.todo("should calculate cap as twice the total insurance value");
    it.todo("should enforce cap limit on payout");
    it.todo("should reduce remaining cap after payout");
    it.todo("should handle zero remaining cap on subsequent claims");
  });

  describe("Claim - Item Matching", () => {
    it.todo("should reject claim with unknown item type");
    it.todo("should reject claim with more item damages than insured");
  });
});

