export interface QuoteRequest {
  yearsWithMHPCO: number;
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimRequest {
  policyIndex: number;
  damages: Array<{
    itemType: string;
    amount: number;
  }>;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export const quote = (customer: QuoteRequest, items: unknown[]): QuoteResult => {
  return {
    premium: undefined as unknown as number,
  };
};

export const claim = (
  customer: QuoteRequest,
  policy: QuoteRequest,
  claimRequest: ClaimRequest
): ClaimResult => {
  return {
    payout: undefined as unknown as number,
    remainingCap: undefined as unknown as number,
  };
};

