  }>;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

interface Item {
  type: string;
}

const itemBasePremiums: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const getItemBasePremium = (item: Item): number => {
  return itemBasePremiums[item.type] ?? 0;
};

export const quote = (customer: QuoteRequest, items: unknown[]): QuoteResult => {
  const basePremium = items.reduce(
    (sum, item) => sum + getItemBasePremium(item as Item),
    0
  );

  return {
    premium: basePremium + 5, // Base premium + processing fee
  };
};

export const claim = (
  customer: QuoteRequest,
  policy: QuoteRequest,
  claimRequest: ClaimRequest
): ClaimResult => {
  return {
    payout: undefined as unknown as number,
    remainingCap: undefined as unknown as number,
  };
};

